// Solution
#include <iostream>
#include <vector>
using namespace std;

void getPairs(std::vector<int>& arr1, std::vector<int>& arr2, int sum) {
    sort(arr1.begin(), arr1.end());
    sort(arr2.begin(), arr2.end());
    int i = 0, j = arr2.size() - 1;
    std::vector<std::pair<int, int>> res;
    while (i < arr1.size() && j >= 0) {
        if (arr1[i] + arr2[j] == sum) {
            res.push_back(std::make_pair(arr1[i], arr2[j]));
            i++; j--;
        } else if (arr1[i] + arr2[j] < sum) {
            i++;
        } else {
            j--;
        }
    }
    cout << "[";
    for (int k = 0; k < res.size(); k++) {
        cout << "[" << res[k].first << ", " << res[k].second << "]";
        if (k != res.size() - 1) {
            cout << ", ";
        }
    }
    cout << " ]" << endl;
}

