// Solution
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Scanner;

public class Solution {
    public static void getPairs(int[] arr1, int[] arr2, int sum) {
        Arrays.sort(arr1);
        Arrays.sort(arr2);
        int i = 0, j = arr2.length - 1;
        java.util.ArrayList<java.util.ArrayList<Integer>> res = new java.util.ArrayList<>();
        while (i < arr1.length && j >= 0) {
            if (arr1[i] + arr2[j] == sum) {
                java.util.ArrayList<Integer> temp = new java.util.ArrayList<>();
                temp.add(arr1[i]); temp.add(arr2[j]);
                res.add(temp);
                i++; j--;
            } else if (arr1[i] + arr2[j] < sum) {
                i++;
            } else {
                j--;
            }
        }
        System.out.print("[[");
        for (int k = 0; k < res.size(); k++) {
            System.out.print("[" + res.get(k).get(0) + ", " + res.get(k).get(1) + "]");
            if (k != res.size() - 1) {
                System.out.print(", ");
            }
        }
        System.out.println(" ]]");
    }
}

